import React from 'react';

function FichePlat({ title, description, image, ingredients }) {
    return (
        <div className="fiche-plat">
            <h2>{title}</h2>
            <img src={image} alt={title} />
            <p>{description}</p>
            <h3>Ingrédients:</h3>
            <ul>
                {ingredients.map((ingredient, index) => (
                    <li key={index}>{ingredient}</li>
                ))}
            </ul>
        </div>
    );
}

export default FichePlat;
